PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE leads (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  product_name  TEXT    NOT NULL,
  name          TEXT    NOT NULL,
  phone         TEXT    NOT NULL,
  email         TEXT,
  city          TEXT,
  value         REAL,
  currency      TEXT    NOT NULL DEFAULT 'PYG',
  fbp           TEXT,
  fbc           TEXT,
  user_agent    TEXT,
  ip            TEXT,
  status        TEXT    NOT NULL DEFAULT 'pending',
  created_at    TEXT    NOT NULL DEFAULT (datetime('now')),
  purchased_at  TEXT
, quantity INTEGER NOT NULL DEFAULT 1, variant TEXT, fbclid        TEXT, utm_source    TEXT, utm_medium    TEXT, utm_campaign  TEXT, utm_content   TEXT, utm_term      TEXT, campaign_id   TEXT, adset_id      TEXT, ad_id         TEXT, campaign_name TEXT, adset_name    TEXT, ad_name       TEXT, landing_path  TEXT, referrer      TEXT, address        TEXT, payment_method TEXT, product_slug TEXT, source_type TEXT, attribution_type TEXT, observation TEXT, capi_status TEXT, capi_event_id TEXT, capi_error TEXT, stock_deducted INTEGER DEFAULT 0, stock_deducted_at TEXT, stock_error TEXT, operational_date_py TEXT, attribution_confidence TEXT, location_address TEXT, location_city TEXT, location_lat REAL, location_lng REAL, location_maps_url TEXT, location_place_id TEXT, session_id TEXT);
CREATE TABLE products (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  slug          TEXT    NOT NULL UNIQUE,
  name          TEXT    NOT NULL,
  stock_total   INTEGER NOT NULL DEFAULT 0,
  variants_json TEXT,
  active        INTEGER NOT NULL DEFAULT 1,
  updated_at    TEXT    NOT NULL DEFAULT (datetime('now'))
, variants_meta_json TEXT, unit_cost     INTEGER DEFAULT 0, default_price INTEGER DEFAULT 0, min_stock     INTEGER DEFAULT 0);
CREATE TABLE behavior_events (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  session_id  TEXT    NOT NULL,
  landing     TEXT    NOT NULL,
  event_type  TEXT    NOT NULL,
  section     TEXT,
  cta_type    TEXT,
  meta        TEXT,
  ts          INTEGER NOT NULL DEFAULT (unixepoch())
);
CREATE TABLE blocked_customers (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  lead_id      INTEGER,
  name         TEXT,
  phone        TEXT,
  ip           TEXT,
  user_agent   TEXT,
  fbp          TEXT,
  fbc          TEXT,
  session_id   TEXT,
  reason       TEXT,
  notes        TEXT,
  active       INTEGER NOT NULL DEFAULT 1,
  created_at   TEXT    NOT NULL DEFAULT (datetime('now')),
  unblocked_at TEXT
);
CREATE TABLE shipping_history (
  id                INTEGER PRIMARY KEY AUTOINCREMENT,
  date              TEXT    NOT NULL UNIQUE,
  delivery_amount   INTEGER NOT NULL DEFAULT 0,
  encomienda_amount INTEGER NOT NULL DEFAULT 0,
  total_shipping    INTEGER NOT NULL DEFAULT 0,
  purchased_count   INTEGER NOT NULL DEFAULT 0,
  per_sale          INTEGER NOT NULL DEFAULT 0,
  dam_finanzas_count INTEGER NOT NULL DEFAULT 0,
  applied_at        TEXT    NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE lead_quality (
  id                    INTEGER PRIMARY KEY AUTOINCREMENT,

  -- Relación con lead original (solo lectura de leads, nunca escritura)
  lead_id               INTEGER NOT NULL UNIQUE,
  session_id            TEXT,
  phone                 TEXT,
  product_slug          TEXT,
  product_name          TEXT,
  city                  TEXT,

  -- Atribución Meta (copiada de leads para análisis aislado)
  campaign_id           TEXT,
  adset_id              TEXT,
  ad_id                 TEXT,
  campaign_name         TEXT,
  adset_name            TEXT,
  ad_name               TEXT,
  attribution_confidence TEXT,

  -- Estado del lead en el momento del snapshot
  status_snapshot       TEXT,  -- purchased / cancelled / blocked / stale / pending

  -- Scoring (0-100, puede ser negativo con penalizaciones)
  quality_score         INTEGER DEFAULT 0,
  quality_label         TEXT,   -- basura / muy_baja / baja / normal / bueno / muy_bueno / excelente
  buyer_type            TEXT,   -- rapido / combo / vip / alto_valor / normal / tardio / vencido / cancelado / bloqueado

  -- Métricas de tiempo
  time_to_purchase_h    REAL,   -- horas desde created_at hasta purchased_at (NULL si no compró)
  lead_age_h            REAL,   -- horas desde created_at hasta el momento del procesamiento

  -- Valor
  total_value           INTEGER,
  is_combo              INTEGER DEFAULT 0,  -- 1 si es combo reloj+cadena
  is_vip                INTEGER DEFAULT 0,  -- 1 si value >= 500.000
  is_fast_buyer         INTEGER DEFAULT 0,  -- 1 si compra en < 24h
  is_high_value         INTEGER DEFAULT 0,  -- 1 si value >= 300.000
  is_dead_lead          INTEGER DEFAULT 0,  -- 1 si venció sin comprar (> 5 días)
  is_cancelled          INTEGER DEFAULT 0,
  is_blocked            INTEGER DEFAULT 0,

  -- Comportamiento (de behavior_events via session_id)
  had_insync_session    INTEGER DEFAULT 0,  -- 1 si hay datos de comportamiento
  scroll_depth          INTEGER,            -- max scroll depth % en la sesión (25/50/75/90)
  cta_clicks            INTEGER DEFAULT 0,
  section_count         INTEGER DEFAULT 0,

  -- Explicación del score
  reason                TEXT,   -- texto libre con la lógica aplicada
  score_version         TEXT DEFAULT 'v1',

  -- Timestamps
  created_at            TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at            TEXT NOT NULL DEFAULT (datetime('now')),
  processed_at          TEXT,   -- cuándo el BQE lo evaluó por última vez
  sent_to_meta_at       TEXT,   -- futuro: si se envía evento a Meta

  FOREIGN KEY (lead_id) REFERENCES leads(id)
);
CREATE TABLE intelligence_run_log (
        id          INTEGER PRIMARY KEY AUTOINCREMENT,
        run_at      TEXT    NOT NULL,
        alerts_sent INTEGER DEFAULT 0,
        source      TEXT    DEFAULT 'cron'
      );
DELETE FROM sqlite_sequence;
CREATE INDEX idx_leads_status      ON leads(status);
CREATE INDEX idx_leads_phone       ON leads(phone);
CREATE INDEX idx_leads_created_at  ON leads(created_at DESC);
CREATE INDEX idx_leads_operational_date ON leads(operational_date_py);
CREATE INDEX idx_leads_location_city ON leads(location_city);
CREATE INDEX idx_be_session  ON behavior_events(session_id);
CREATE INDEX idx_be_type     ON behavior_events(event_type);
CREATE INDEX idx_be_ts       ON behavior_events(ts DESC);
CREATE INDEX idx_be_landing  ON behavior_events(landing);
CREATE INDEX idx_be_section  ON behavior_events(section);
CREATE INDEX idx_be_cta      ON behavior_events(cta_type);
CREATE INDEX idx_leads_session_id ON leads(session_id);
CREATE INDEX idx_bc_phone  ON blocked_customers(phone);
CREATE INDEX idx_bc_ip     ON blocked_customers(ip);
CREATE INDEX idx_bc_active ON blocked_customers(active);
CREATE INDEX idx_lq_lead_id       ON lead_quality(lead_id);
CREATE INDEX idx_lq_ad_id         ON lead_quality(ad_id);
CREATE INDEX idx_lq_adset_id      ON lead_quality(adset_id);
CREATE INDEX idx_lq_campaign_id   ON lead_quality(campaign_id);
CREATE INDEX idx_lq_status        ON lead_quality(status_snapshot);
CREATE INDEX idx_lq_score         ON lead_quality(quality_score);
CREATE INDEX idx_lq_processed     ON lead_quality(processed_at);
CREATE INDEX idx_lq_product       ON lead_quality(product_slug);
CREATE INDEX idx_lq_buyer_type    ON lead_quality(buyer_type);
CREATE INDEX idx_lq_is_dead       ON lead_quality(is_dead_lead);
